mapper.sql:
/* StockAccountHistoryMapper.stockAccountHistoryAccountWhere: 주식계좌이력 계좌 공통 조건 */
WHERE 1 = 1

   AND H.STOCK_ACCOUNT_CD IN

     #{stockAccountCd}

mapper.select:
/* StockAccountHistoryMapper.getLatestStockAccountHistoryDate: 입출금과 확인금액의 최신 기준일 조회 */ SELECT MAX(LATEST_DT) FROM ( SELECT MAX(REPLACE(H.CASH_DT, '-', '')) AS LATEST_DT FROM MY_STOCK_ACCOUNT_CASH_HISTORY H JOIN COMMON_CODE SA ON SA.GRP_CD = 'STOCK_ACCOUNT' AND SA.CD = H.STOCK_ACCOUNT_CD AND SA.USE_YN = 'Y'
UNION ALL SELECT MAX(REPLACE(H.CASH_DT, '-', '')) AS LATEST_DT FROM MY_STOCK_ACCOUNT_STOCK_CHECK H JOIN COMMON_CODE SA ON SA.GRP_CD = 'STOCK_ACCOUNT' AND SA.CD = H.STOCK_ACCOUNT_CD AND SA.USE_YN = 'Y'
) LATEST_SOURCE

mapper.update:
/* StockAccountHistoryMapper.updateStockAccountCheckAmount: 계좌와 확인일이 같은 확인 평가금 수정 */
UPDATE MY_STOCK_ACCOUNT_STOCK_CHECK
   SET STOCK_TOTAL_AMT = #{stockTotalAmt}
     , UDT_NO = #{udtNo}
     , UDT_DT = NOW()
 WHERE CASH_DT = #{checkDt}
   AND STOCK_ACCOUNT_CD = #{stockAccountCd}

mapper.insert:
/* StockAccountHistoryMapper.insertStockAccountCheckAmount: 계좌 확인 평가금 등록 */
INSERT INTO MY_STOCK_ACCOUNT_STOCK_CHECK
(
       CASH_DT
     , STOCK_ACCOUNT_CD
     , STOCK_TOTAL_AMT
     , REG_NO
     , REG_DT
     , UDT_NO
     , UDT_DT
)
VALUES
(
       #{checkDt}
     , #{stockAccountCd}
     , #{stockTotalAmt}
     , #{regNo}
     , NOW()
     , #{udtNo}
     , NOW()
)

/* StockAccountHistoryMapper.insertStockAccountCashHistory: 계좌 입출금 이력 등록 */
INSERT INTO MY_STOCK_ACCOUNT_CASH_HISTORY
(
       CASH_DT
     , STOCK_ACCOUNT_CD
     , CASH_IN_OUT_CD
     , CASH_AMT
     , REG_NO
     , REG_DT
     , UDT_NO
     , UDT_DT
)
VALUES
(
       #{cashDt}
     , #{stockAccountCd}
     , #{cashInOutCd}
     , #{cashAmt}
     , #{regNo}
     , NOW()
     , #{udtNo}
     , NOW()
)
